update public.questions set source_quote = '«الرقية الشرعية جائزة، وقد كان النبي ﷺ يرقي ويُرقى»' where id = 'c68cab87-c801-4d1f-bd2f-869373b36903';
update public.questions set source_quote = '«التبرك بالأشجار والأحجار بنية جلب النفع أو دفع الضر شرك»' where id = '1cb55316-5773-4fd4-9cbc-ed8a3ad77fcf';
update public.questions set source_quote = '«مر رجل على قوم لهم صنم لا يجوز أحد حتى يُقرب له شيئاً»' where id = 'fcbcf713-b692-4fbf-a3e4-097b3dcb5320';
update public.questions set source_quote = '«النذر عبادة لا تصرف إلا لله، والنذر لغير الله كالأضرحة شرك»' where id = '8b90c623-9d83-4b86-ae85-46e901a301ec';
update public.questions set source_quote = '«تعلم السحر كفر، لأنه يستعان فيه بالشياطين»' where id = 'c4723bbb-7b5e-4367-a261-897ac2764355';
update public.questions set source_quote = '«الخوف الطبيعي جائز، أما الخوف التعبدي الذي يصرف لغير الله فهو شرك»' where id = '7be4404c-a2ed-4095-b440-c88f49d56a10';
update public.questions set source_quote = '«محبة غير اللهم ح ب ة كحب الله أو أشد شرك أكبر»' where id = '0f1efff9-1444-4eb2-a109-250d262cb098';
update public.questions set source_quote = '«منحلفبغيرللافقدكفرأوأشرك»' where id = 'd3ef73b7-d767-4445-a6d7-c1f92032be45';
update public.questions set source_quote = '«أول واجب على المكلف: التوحيد»' where id = 'da419f24-e82d-4e63-800d-0bde0f05c9d2';
update public.questions set source_quote = '«الرقية المحرمة: ما كان فيها استعانة بالجن أو بأسماء مجهولة»' where id = 'c456ef68-5e71-4cfe-8712-e1bcadd8ca07';
update public.questions set source_quote = '«التبرك بغير ما ورد بها ل ش ر ع يعتبر شركا إذا اعتقد أن ذلك الشيء يبارك بذاته»' where id = '93710d33-5a37-4812-9ff4-5b4b44916ad5';
update public.questions set source_quote = '«النبي ﷺ أذن للرجل بالوفاء بنذره بعد أن سأله: هل كان فيها وثن يعبد أو عيد لهم»' where id = 'df5108ef-c680-4871-90b4-f87d718b4d57';
update public.questions set source_quote = '«توسلوا إلى الله بأعمالهم الصالحة كبر الوالدين والعفاف»' where id = '3cedf36e-e899-4336-be8f-e6f4a279cdaa';
update public.questions set source_quote = '«علامة صدق محبة الله: أن يكون الله ورسوله أحب إليه مما سواهما»' where id = '0b79cc37-e91a-43e2-b864-f3435b7b633b';
update public.questions set source_quote = '«السحر لا يتعلم إلا بعبادة الشياطين»' where id = 'f810ad04-6a66-4c32-b8fe-47d23f1c8b75';
update public.questions set source_quote = '«الحديث يأمر بالحرص على الخير وفعل الأسباب مع الاستعانة بالله»' where id = '3c25460f-3ac5-43d1-9aec-fc24349f558d';
update public.questions set source_quote = '«التطير شرك لأنه اعتقاد أن ما يتشاءم به يجلب الضر»' where id = '6e55abe0-45c5-4cb2-a74a-6f97e74dbd6f';
update public.questions set source_quote = '«الرياء: إظهار العبادة ليرى، والسمعة: التحدث بها ليسمع»' where id = '288554fc-7b6d-4532-b1a7-018cb647e5e2';
update public.questions set source_quote = '«الشرك ظلم عظيم لأنه يتضمن التسوية بين الخالق والمخلوق»' where id = '80bc1390-88d3-4749-b6f5-8ec7faf53c88';
update public.questions set source_quote = '«من صدق كاهنا أو منجما بما يخبر به منا ل غ ي ب فقد كفر»' where id = 'a8f23c47-fc66-475b-932a-466229070465';
update public.questions set source_quote = '«التوسل بالجاه لم يرد عن السلف، وهو ذريعة إلى الشرك»' where id = '34f0da6e-4ab8-4721-b1eb-1105c59d76f2';
update public.questions set source_quote = '«نسبة المطر إلى النجم شرك»' where id = '13d43d42-9990-4713-b002-fb1a5a675b9c';
update public.questions set source_quote = '«وصف الله المنافقين بأنهم يراؤون الناس في صلاتهم وعبادتهم»' where id = 'a0843318-ca13-4eb8-8738-14b57dcb6919';
update public.questions set source_quote = '«لأنه خوف تعبدي صرف لغير الله»' where id = 'fb26ac3b-5e44-4831-89a2-446a7b7efa67';
update public.questions set source_quote = '«لأنه لا يتوصل إليه إلا بالاستعانة بالشياطين»' where id = '213fc1f9-d919-4153-b28a-6e53cb13acce';
